import {
  forwardRef,
  useCallback,
  useEffect,
  useId,
  useImperativeHandle,
  useLayoutEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import { createPortal } from 'react-dom';
import type { Placement, PositionResult } from '@o9ds/core';
import { computePosition, createPositionWatcher, filterItems, filterGroups } from '@o9ds/core';
import type { ListItemBase, ListGroup } from '@o9ds/core';
import { useOverlay } from '../../hooks/useOverlay';
import { useListNavigation } from '../../hooks/useListNavigation';
import { useTooltip } from '../../hooks/useTooltip';
import { FormLabel } from '../FormLabel';
import O9Search from '../Search/Search';
import type { MenuSearchProp } from '../../types/menu-search';
import { normalizeSearch } from '../../types/menu-search';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface SelectOptionData extends ListItemBase {
  value: unknown;
}

export interface O9SelectProps {
  items: SelectOptionData[] | ListGroup<SelectOptionData>[];
  value?: unknown;
  defaultValue?: unknown;
  placeholder?: string;
  label?: string;
  isDisabled?: boolean;
  isRequired?: boolean;
  isInvalid?: boolean;
  errorMsg?: string;
  isInlineError?: boolean;
  size?: 'sm' | 'lg';
  /** Enable search with defaults (`true`) or pass a config object. */
  search?: MenuSearchProp;
  isLoading?: boolean;
  isReadOnly?: boolean;
  width?: string;
  isFullWidth?: boolean;
  placement?: 'top-start' | 'top-end' | 'bottom-start' | 'bottom-end' | 'auto';
  maxHeight?: string;
  hasGroupDividers?: boolean;
  closeOnSelect?: boolean;
  isOpen?: boolean;
  defaultOpen?: boolean;
  onChange?: (item: SelectOptionData | null, index: number) => boolean | void;
  onOpen?: () => boolean | void;
  onClose?: () => boolean | void;
  onOpenChange?: (isOpen: boolean) => void;
  className?: string;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function isGrouped(
  items: SelectOptionData[] | ListGroup<SelectOptionData>[],
): items is ListGroup<SelectOptionData>[] {
  return items.length > 0 && 'items' in items[0];
}

function flattenItems(
  items: SelectOptionData[] | ListGroup<SelectOptionData>[],
): SelectOptionData[] {
  if (isGrouped(items)) return items.flatMap((g) => g.items);
  return items as SelectOptionData[];
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

const O9Select = forwardRef<HTMLDivElement, O9SelectProps>(
  function O9Select(
    {
      items,
      value,
      defaultValue,
      placeholder,
      label,
      isDisabled = false,
      isRequired = false,
      isInvalid = false,
      errorMsg,
      isInlineError = false,
      size = 'lg',
      search,
      isLoading = false,
      isReadOnly = false,
      width,
      isFullWidth = false,
      placement = 'bottom-start',
      maxHeight,
      hasGroupDividers = true,
      closeOnSelect = true,
      isOpen: openProp,
      defaultOpen = false,
      onChange,
      onOpen,
      onClose,
      onOpenChange,
      className,
    },
    ref,
  ) {
    const uid = useId();
    const selId = `o9ds-sel-${uid}`;
    const panelId = `${selId}-panel`;
    const labelId = `${selId}-lbl`;
    const inputId = `${selId}-input`;
    const errorId = `${selId}-err`;

    const searchCfg = useMemo(
      () => normalizeSearch(search),
      [search],
    );

    const rootRef = useRef<HTMLDivElement>(null);
    const fieldRef = useRef<HTMLDivElement>(null);
    const triggerRef = useRef<HTMLDivElement>(null);
    const panelRef = useRef<HTMLDivElement>(null);
    const searchWrapperRef = useRef<HTMLDivElement>(null);
    const errIcoRef = useRef<HTMLSpanElement>(null);

    useImperativeHandle(ref, () => rootRef.current!, []);

    useTooltip({
      triggerRef: errIcoRef,
      tooltip: isInlineError && isInvalid && errorMsg ? errorMsg : undefined,
    });

    // ── Controlled / Uncontrolled open ─────────────────────────────────
    const isControlled = openProp !== undefined;
    const [internalOpen, setInternalOpen] = useState(defaultOpen);
    const isOpen = isControlled ? openProp! : internalOpen;

    const setOpen = useCallback(
      (next: boolean) => {
        if (!isControlled) setInternalOpen(next);
        onOpenChange?.(next);
      },
      [isControlled, onOpenChange],
    );

    // ── Controlled / Uncontrolled value ────────────────────────────────
    const isValueControlled = value !== undefined;
    const [internalValue, setInternalValue] = useState<unknown>(
      defaultValue ?? null,
    );
    const currentValue = isValueControlled ? value : internalValue;

    // ── Filter state ───────────────────────────────────────────────────
    const [filterQuery, setFilterQuery] = useState('');

    const filteredItems = useMemo(() => {
      if (!searchCfg || !filterQuery) return items;
      if (isGrouped(items)) {
        return filterGroups(items, { query: filterQuery });
      }
      return filterItems(items as SelectOptionData[], { query: filterQuery });
    }, [items, searchCfg, filterQuery]);

    const flatItems = useMemo(
      () => flattenItems(filteredItems),
      [filteredItems],
    );

    const totalItemCount = useMemo(() => flattenItems(items).length, [items]);

    useEffect(() => {
      if (searchCfg && filterQuery) {
        searchCfg.onFilter?.(filterQuery, flatItems.length);
      }
    }, [searchCfg, filterQuery, flatItems.length]);

    // ── Selected item lookup (against unfiltered list) ─────────────────
    const selectedItem = useMemo(() => {
      if (currentValue == null) return null;
      const allFlat = flattenItems(items);
      return allFlat.find((item) => item.value === currentValue) ?? null;
    }, [currentValue, items]);

    // ── Overlay hub ────────────────────────────────────────────────────
    const overlay = useOverlay();

    // ── Close handler ──────────────────────────────────────────────────
    const handleClose = useCallback(() => {
      if (!isOpen) return;
      if (onClose?.() === false) return;

      setOpen(false);
      setFilterQuery('');
      overlay.close(selId);
      triggerRef.current?.focus({ preventScroll: true });
      rootRef.current?.dispatchEvent(
        new CustomEvent('sel:close', { bubbles: true, cancelable: true }),
      );
    }, [isOpen, onClose, setOpen, overlay, selId]);

    // ── Open handler ───────────────────────────────────────────────────
    const handleOpen = useCallback(() => {
      if (isOpen || isDisabled || isLoading || isReadOnly) return;
      if (onOpen?.() === false) return;

      setOpen(true);
      rootRef.current?.dispatchEvent(
        new CustomEvent('sel:open', { bubbles: true, cancelable: true }),
      );
    }, [isOpen, isDisabled, isLoading, isReadOnly, onOpen, setOpen]);

    const toggleOpen = useCallback(() => {
      if (isOpen) handleClose();
      else handleOpen();
    }, [isOpen, handleOpen, handleClose]);

    // ── Placeholder selection handler ──────────────────────────────────
    const handlePlaceholderSelect = useCallback(() => {
      const result = onChange?.(null, -1);

      if (!isValueControlled) {
        setInternalValue(null);
      }

      rootRef.current?.dispatchEvent(
        new CustomEvent('sel:change', {
          bubbles: true,
          cancelable: true,
          detail: { item: null, index: -1 },
        }),
      );

      if (result !== false && closeOnSelect) {
        handleClose();
      }
    }, [onChange, isValueControlled, closeOnSelect, handleClose]);

    // ── Selection handler ──────────────────────────────────────────────
    const handleSelect = useCallback(
      (item: SelectOptionData, index: number) => {
        if (item.isDisabled) return;
        const result = onChange?.(item, index);

        if (!isValueControlled) {
          setInternalValue(item.value);
        }

        rootRef.current?.dispatchEvent(
          new CustomEvent('sel:change', {
            bubbles: true,
            cancelable: true,
            detail: { item, index },
          }),
        );

        if (result !== false && closeOnSelect) {
          handleClose();
        }
      },
      [onChange, isValueControlled, closeOnSelect, handleClose],
    );

    // ── Effective flat items (with placeholder prepended for nav) ──────
    const hasPlaceholder = !!placeholder;
    const effectiveOffset = hasPlaceholder ? 1 : 0;

    // ── List navigation ────────────────────────────────────────────────
    const keyboardActiveRef = useRef(false);

    const handleItemSelect = useCallback(
      (item: ListItemBase, index: number) => {
        if (hasPlaceholder && index === 0) {
          handlePlaceholderSelect();
          return;
        }
        const realIndex = index - effectiveOffset;
        handleSelect(flatItems[realIndex], realIndex);
      },
      [handleSelect, handlePlaceholderSelect, hasPlaceholder, effectiveOffset, flatItems],
    );

    const navItems = useMemo(() => {
      if (!hasPlaceholder) return flatItems;
      const placeholderItem: ListItemBase = { id: '__placeholder__', label: placeholder! };
      return [placeholderItem, ...flatItems];
    }, [hasPlaceholder, placeholder, flatItems]);

    const scrollToIndex = useCallback(
      (index: number) => {
        keyboardActiveRef.current = true;
        const el = panelRef.current?.querySelector(
          `[data-index="${index}"]`,
        ) as HTMLElement | null;
        if (el) {
          el.scrollIntoView({ block: 'nearest' });
          el.focus({ preventScroll: true });
        }
      },
      [],
    );

    const { activeIndex, setActiveIndex, handleKeyDown: navKeyDown } =
      useListNavigation({
        items: navItems,
        onSelect: handleItemSelect,
        onEscape: handleClose,
        wrap: true,
        enabled: isOpen,
        scrollToIndex,
      });

    useEffect(() => {
      if (isOpen) {
        keyboardActiveRef.current = false;
        const firstEnabled = navItems.findIndex((item) => !item.isDisabled);
        setActiveIndex(firstEnabled >= 0 ? firstEnabled : 0);
      }
    }, [isOpen, navItems, setActiveIndex]);

    // ── Item click handler ─────────────────────────────────────────────
    const handleItemClick = useCallback(
      (item: SelectOptionData, dataIndex: number) => {
        if (item.isDisabled || isLoading) return;
        setActiveIndex(dataIndex);
        const realIndex = dataIndex - effectiveOffset;
        handleSelect(item, realIndex);
      },
      [isLoading, setActiveIndex, handleSelect, effectiveOffset],
    );

    // ── Field click handler ────────────────────────────────────────────
    const handleFieldClick = useCallback(() => {
      if (isDisabled || isLoading || isReadOnly) return;
      toggleOpen();
    }, [isDisabled, isLoading, isReadOnly, toggleOpen]);

    // ── Overlay hub registration ───────────────────────────────────────
    useEffect(() => {
      if (!isOpen || !panelRef.current) return;
      overlay.open({
        id: selId,
        type: 'dropdown',
        element: panelRef.current,
        triggerElement: triggerRef.current ?? undefined,
        priority: 20,
        config: { autoCloseOnOutsideClick: true },
        onClose: handleClose,
      });
      return () => {
        overlay.close(selId);
      };
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isOpen]);

    // ── Positioning (imperative — bypasses React state to avoid flicker) ─
    const posRef = useRef<PositionResult | null>(null);
    const posWatcherRef = useRef<ReturnType<typeof createPositionWatcher> | null>(null);

    useLayoutEffect(() => {
      if (!isOpen) {
        posRef.current = null;
        posWatcherRef.current?.destroy();
        posWatcherRef.current = null;
        return;
      }

      const anchor = fieldRef.current;
      const float = panelRef.current;
      if (!anchor || !float) return;

      const opts = { placement: placement as Placement, gap: 2, width: 'anchor' as const };

      const applyPosition = (pos: PositionResult) => {
        float.style.transform = `translate(${pos.x}px, ${pos.y}px)`;
        if (pos.width) {
          float.style.width = pos.width;
          float.style.minWidth = pos.width;
        }
        if (pos.maxHeight != null) {
          float.style.maxHeight = `${pos.maxHeight}px`;
        }
      };

      const anchorWidth = `${anchor.getBoundingClientRect().width}px`;
      float.style.width = anchorWidth;
      float.style.minWidth = anchorWidth;

      const pos = computePosition(anchor, float, opts);
      posRef.current = pos;
      applyPosition(pos);
      float.style.visibility = '';

      const watcher = createPositionWatcher(anchor, float, opts, (result) => {
        posRef.current = result;
        applyPosition(result);
      });
      posWatcherRef.current = watcher;

      return () => {
        watcher.destroy();
        posWatcherRef.current = null;
      };
    }, [isOpen, placement]);

    // ── Outside click ──────────────────────────────────────────────────
    useEffect(() => {
      if (!isOpen) return;
      const onPointerDown = (e: PointerEvent) => {
        const target = e.target as Node;
        if (panelRef.current?.contains(target)) return;
        if (rootRef.current?.contains(target)) return;
        handleClose();
      };
      document.addEventListener('pointerdown', onPointerDown, true);
      return () =>
        document.removeEventListener('pointerdown', onPointerDown, true);
    }, [isOpen, handleClose]);

    // ── Focus guard — close if focus escapes component scope ────────────
    useEffect(() => {
      if (!isOpen) return;
      const onFocusIn = (e: FocusEvent) => {
        const target = e.target as Node;
        if (rootRef.current?.contains(target)) return;
        if (panelRef.current?.contains(target)) return;
        handleClose();
      };
      document.addEventListener('focusin', onFocusIn);
      return () => document.removeEventListener('focusin', onFocusIn);
    }, [isOpen, handleClose]);

    // ── Focus search input when panel opens ─────────────────────────────
    useEffect(() => {
      if (!isOpen || !searchCfg) return;
      requestAnimationFrame(() => {
        const input = searchWrapperRef.current?.querySelector('input');
        input?.focus();
      });
    }, [isOpen, searchCfg]);

    // ── Trigger keyboard handler ───────────────────────────────────────
    const handleTriggerKeyDown = useCallback(
      (e: React.KeyboardEvent) => {
        if (isDisabled || isLoading) return;

        if (!isOpen) {
          if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            handleOpen();
            return;
          }
          if (e.key === 'ArrowDown') {
            e.preventDefault();
            handleOpen();
            return;
          }
          if (e.key === 'ArrowUp') {
            e.preventDefault();
            handleOpen();
            return;
          }
          if (e.key.length === 1 && !e.ctrlKey && !e.metaKey && !e.altKey) {
            const allFlat = flattenItems(items);
            const char = e.key.toLowerCase();
            const currentIdx =
              currentValue != null
                ? allFlat.findIndex((item) => item.value === currentValue)
                : -1;

            for (let i = 1; i <= allFlat.length; i++) {
              const idx = (currentIdx + i) % allFlat.length;
              const item = allFlat[idx];
              if (
                !item.isDisabled &&
                item.label.toLowerCase().startsWith(char)
              ) {
                if (!isValueControlled) setInternalValue(item.value);
                onChange?.(item, idx);
                rootRef.current?.dispatchEvent(
                  new CustomEvent('sel:change', {
                    bubbles: true,
                    cancelable: true,
                    detail: { item, index: idx },
                  }),
                );
                break;
              }
            }
          }
          return;
        }

        if (e.key === 'Tab') {
          e.preventDefault();
          if (activeIndex >= 0 && activeIndex < navItems.length) {
            const navItem = navItems[activeIndex];
            if (hasPlaceholder && activeIndex === 0) {
              handlePlaceholderSelect();
              return;
            }
            if (!navItem.isDisabled) {
              const realIndex = activeIndex - effectiveOffset;
              handleSelect(flatItems[realIndex], realIndex);
              return;
            }
          }
          handleClose();
          return;
        }

        navKeyDown(e);
      },
      [
        isDisabled,
        isLoading,
        isOpen,
        items,
        currentValue,
        isValueControlled,
        onChange,
        handleOpen,
        handleClose,
        navKeyDown,
        navItems,
        flatItems,
        activeIndex,
        handleSelect,
        handlePlaceholderSelect,
        hasPlaceholder,
        effectiveOffset,
      ],
    );

    // ── Search handlers (O9Search callbacks) ────────────────────────────
    const handleFilterSearch = useCallback(
      (value: string) => {
        setFilterQuery(value);
        setActiveIndex(0);
      },
      [setActiveIndex],
    );

    const handleFilterClear = useCallback(() => {
      setFilterQuery('');
      setActiveIndex(0);
      searchCfg?.onClear?.();
    }, [setActiveIndex, searchCfg]);

    const handleSearchWrapperKeyDown = useCallback(
      (e: React.KeyboardEvent<HTMLDivElement>) => {
        switch (e.key) {
          case 'ArrowDown':
          case 'ArrowUp':
          case 'Home':
          case 'End':
            e.preventDefault();
            navKeyDown(e);
            break;
          case 'Enter':
            e.preventDefault();
            if (activeIndex >= 0 && activeIndex < navItems.length) {
              if (hasPlaceholder && activeIndex === 0) {
                handlePlaceholderSelect();
              } else {
                const navItem = navItems[activeIndex];
                if (!navItem.isDisabled) {
                  const realIndex = activeIndex - effectiveOffset;
                  handleSelect(flatItems[realIndex], realIndex);
                }
              }
            }
            break;
          case 'Escape':
            if (!filterQuery) {
              e.preventDefault();
              handleClose();
            }
            break;
          case 'Tab':
            e.preventDefault();
            if (activeIndex >= 0 && activeIndex < navItems.length) {
              if (hasPlaceholder && activeIndex === 0) {
                handlePlaceholderSelect();
                return;
              }
              const navItem = navItems[activeIndex];
              if (!navItem.isDisabled) {
                const realIndex = activeIndex - effectiveOffset;
                handleSelect(flatItems[realIndex], realIndex);
                return;
              }
            }
            handleClose();
            break;
        }
      },
      [navKeyDown, activeIndex, navItems, flatItems, handleSelect, handleClose, filterQuery, handlePlaceholderSelect, hasPlaceholder, effectiveOffset],
    );

    // ── CSS classes ────────────────────────────────────────────────────
    const classes = [
      'o9ds-sel',
      `o9ds-sel--${size}`,
      isFullWidth && 'o9ds-sel--full-width',
      searchCfg && 'o9ds-sel--filterable',
      isLoading && 'loading',
      isDisabled && 'is-disabled',
      isReadOnly && 'is-readonly',
      isInvalid && 'has-error',
      isInvalid && isInlineError && 'error-inline',
      isOpen && 'open',
      currentValue != null && 'has-value',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    // ── Root style (width) ─────────────────────────────────────────────
    const rootStyle: React.CSSProperties | undefined = (() => {
      const effectiveWidth = isFullWidth ? '100%' : width;
      if (!effectiveWidth) return undefined;
      return { '--o9ds-form-input-width': effectiveWidth } as React.CSSProperties;
    })();

    // ── Panel style ────────────────────────────────────────────────────
    const pos = posRef.current;
    const panelStyle: React.CSSProperties = {
      ...(pos
        ? {
            transform: `translate(${pos.x}px, ${pos.y}px)`,
            ...(pos.width ? { width: pos.width, minWidth: pos.width } : {}),
            ...(pos.maxHeight ? { maxHeight: `${pos.maxHeight}px` } : {}),
          }
        : { visibility: 'hidden' }),
      ...(maxHeight
        ? ({
            '--o9ds-sel-panel-max-height': maxHeight,
          } as React.CSSProperties)
        : {}),
      ...(isLoading ? { pointerEvents: 'none' as const } : {}),
    };

    // ── Option rendering ───────────────────────────────────────────────
    const renderOption = (item: SelectOptionData, dataIndex: number) => {
      const isSelected = item.value === currentValue;
      const isHighlighted = dataIndex === activeIndex;
      const optClasses = [
        'o9ds-sel__opt',
        item.isDisabled && 'is-disabled',
        isHighlighted && keyboardActiveRef.current && 'focused',
        isSelected && 'active',
      ]
        .filter(Boolean)
        .join(' ');

      return (
        <div
          key={item.id}
          id={`${selId}-opt-${dataIndex}`}
          className={optClasses}
          role="option"
          aria-selected={isSelected}
          aria-disabled={item.isDisabled || undefined}
          data-index={dataIndex}
          onClick={() => handleItemClick(item, dataIndex)}
          onMouseEnter={() => {
            if (!item.isDisabled) {
              keyboardActiveRef.current = false;
              setActiveIndex(dataIndex);
            }
          }}
        >
          {item.icon && (
            <span
              className={`o9ds-sel__opt__ico o9con o9con-${item.icon}`}
              aria-hidden="true"
            />
          )}
          <div className="o9ds-sel__opt__txt">
            <span className="o9ds-sel__opt__lbl">{item.label}</span>
          </div>
        </div>
      );
    };

    // ── Placeholder option rendering ───────────────────────────────────
    const renderPlaceholderOption = () => {
      if (!hasPlaceholder) return null;
      const dataIndex = 0;
      const isNoValue = currentValue == null;
      const isHighlighted = dataIndex === activeIndex;
      const optClasses = [
        'o9ds-sel__opt',
        'o9ds-sel__opt--placeholder',
        isHighlighted && keyboardActiveRef.current && 'focused',
      ]
        .filter(Boolean)
        .join(' ');

      return (
        <div
          key="__placeholder__"
          id={`${selId}-opt-${dataIndex}`}
          className={optClasses}
          role="option"
          aria-selected={isNoValue}
          data-index={dataIndex}
          onClick={() => {
            if (isLoading) return;
            setActiveIndex(dataIndex);
            handlePlaceholderSelect();
          }}
          onMouseEnter={() => {
            keyboardActiveRef.current = false;
            setActiveIndex(dataIndex);
          }}
        >
          <div className="o9ds-sel__opt__txt">
            <span className="o9ds-sel__opt__lbl">{placeholder}</span>
          </div>
        </div>
      );
    };

    // ── Content rendering (flat vs grouped) ────────────────────────────
    const renderContent = () => {
      if (flatItems.length === 0 && !hasPlaceholder) {
        return (
          <div className="o9ds-sel__empty" role="status">
            No results
          </div>
        );
      }

      const placeholderNode = renderPlaceholderOption();

      if (isGrouped(filteredItems)) {
        let dataIndex = effectiveOffset;
        return (
          <>
            {placeholderNode}
            {(filteredItems as ListGroup<SelectOptionData>[]).map(
              (group, groupIdx) => (
                <div key={group.id} role="group" aria-label={group.label}>
                  {groupIdx > 0 && hasGroupDividers && (
                    <hr className="o9ds-sel__divider" role="separator" />
                  )}
                  {group.label && (
                    <div className="o9ds-sel__hdr">{group.label}</div>
                  )}
                  {group.items.map((item) => {
                    const node = renderOption(item, dataIndex);
                    dataIndex++;
                    return node;
                  })}
                </div>
              ),
            )}
          </>
        );
      }

      return (
        <>
          {placeholderNode}
          {(filteredItems as SelectOptionData[]).map((item, i) =>
            renderOption(item, i + effectiveOffset),
          )}
        </>
      );
    };

    // ── Panel classes ──────────────────────────────────────────────────
    const panelClasses = [
      'o9ds-sel__panel',
      isOpen && 'open',
    ].filter(Boolean).join(' ');

    // ── Panel (portaled) ───────────────────────────────────────────────
    const panel = isOpen
      ? createPortal(
          <div
            className={`o9ds-sel o9ds-sel--${size}`}
            style={{ display: 'contents' }}
          >
            <div
              ref={panelRef}
              id={panelId}
              className={panelClasses}
              role="listbox"
              aria-busy={isLoading || undefined}
              style={
                Object.keys(panelStyle).length > 0 ? panelStyle : undefined
              }
            >
              {searchCfg && (
                <div
                  ref={searchWrapperRef}
                  className={[
                    'o9ds-sel__search',
                    searchCfg.className,
                  ].filter(Boolean).join(' ')}
                  onKeyDown={handleSearchWrapperKeyDown}
                >
                  <O9Search
                    variant="filter"
                    value={filterQuery}
                    placeholder={searchCfg.placeholder}
                    searchMode={searchCfg.searchMode}
                    minChars={searchCfg.minChars}
                    isClearable={searchCfg.isClearable}
                    shortcut={searchCfg.shortcut}
                    errorMsg={searchCfg.errorMsg}
                    isInlineError
                    counter={
                      searchCfg.counter && filterQuery
                        ? { current: flatItems.length, total: totalItemCount }
                        : null
                    }
                    onSearch={handleFilterSearch}
                    onClear={handleFilterClear}
                    isDisabled={isDisabled}
                    aria-label="Filter options"
                  />
                </div>
              )}
              <div className="o9ds-sel__scroll">{renderContent()}</div>
            </div>
          </div>,
          document.body,
        )
      : null;

    // ── Render ──────────────────────────────────────────────────────────
    return (
      <div ref={rootRef} className={classes} style={rootStyle}>
        {label && (
          <FormLabel
            htmlFor={inputId}
            id={labelId}
            size={size === 'sm' ? 'sm' : 'lg'}
            isRequired={isRequired}
            isDisabled={isDisabled}
            className="o9ds-sel__lbl"
          >
            {label}
          </FormLabel>
        )}
        <div
          ref={fieldRef}
          className="o9ds-sel__field"
          onClick={handleFieldClick}
        >
          <div
            ref={triggerRef}
            id={inputId}
            className="o9ds-sel__input"
            role="combobox"
            tabIndex={isDisabled ? -1 : 0}
            aria-haspopup="listbox"
            aria-expanded={isOpen}
            aria-controls={panelId}
            aria-activedescendant={
              isOpen && activeIndex >= 0 && !searchCfg
                ? `${selId}-opt-${activeIndex}`
                : undefined
            }
            aria-required={isRequired || undefined}
            aria-invalid={isInvalid || undefined}
            aria-disabled={isDisabled || undefined}
            aria-busy={isLoading || undefined}
            aria-labelledby={label ? labelId : undefined}
            aria-describedby={isInvalid && errorMsg ? errorId : undefined}
            onKeyDown={handleTriggerKeyDown}
          >
            {selectedItem ? (
              selectedItem.label
            ) : placeholder ? (
              <span className="o9ds-sel__placeholder">{placeholder}</span>
            ) : null}
          </div>
          {isInlineError && isInvalid && (
            <span ref={errIcoRef} className="o9ds-sel__err-ico" aria-hidden="true" />
          )}
          <span
            className="o9ds-sel__ico o9con o9con-angle-down"
            aria-hidden="true"
          />
          <div className="o9ds-sel__border" />
        </div>
        {isInvalid && !isInlineError && errorMsg && (
          <div
            className="o9ds-inline-alert o9ds-inline-alert--error"
            id={errorId}
            role="alert"
          >
            <span className="o9ds-inline-alert__ico" aria-hidden="true" />
            <span className="o9ds-inline-alert__msg">{errorMsg}</span>
          </div>
        )}
        {panel}
      </div>
    );
  },
);

export { O9Select };
export default O9Select;
